    fn update_object_packet_count_like_cpp(packets: &[Vec<u8>]) -> usize {
        packets
            .iter()
            .filter(|bytes| {
                wow_packet::WorldPacket::from_bytes(bytes).server_opcode()
                    == Some(ServerOpcodes::UpdateObject)
            })
            .count()
    }

